import React from "react";

function Shop() {
  const products = [
    { id: 1, name: "Smartphone", price: 499, image: "https://via.placeholder.com/200?text=Smartphone" },
    { id: 2, name: "Laptop", price: 899, image: "https://via.placeholder.com/200?text=Laptop" },
    { id: 3, name: "Headphones", price: 99, image: "https://via.placeholder.com/200?text=Headphones" },
    { id: 4, name: "Smartwatch", price: 199, image: "https://via.placeholder.com/200?text=Smartwatch" },
    { id: 5, name: "Tablet", price: 299, image: "https://via.placeholder.com/200?text=Tablet" },
    { id: 6, name: "Camera", price: 599, image: "https://via.placeholder.com/200?text=Camera" },
    { id: 7, name: "Keyboard", price: 49, image: "https://via.placeholder.com/200?text=Keyboard" },
    { id: 8, name: "Mouse", price: 29, image: "https://via.placeholder.com/200?text=Mouse" },
    { id: 9, name: "Speaker", price: 79, image: "https://via.placeholder.com/200?text=Speaker" },
    { id: 10, name: "Monitor", price: 249, image: "https://via.placeholder.com/200?text=Monitor" },
    { id: 11, name: "Printer", price: 149, image: "https://via.placeholder.com/200?text=Printer" },
    { id: 12, name: "Router", price: 89, image: "https://via.placeholder.com/200?text=Router" },
    { id: 13, name: "External HDD", price: 129, image: "https://via.placeholder.com/200?text=External+HDD" },
    { id: 14, name: "USB Drive", price: 19, image: "https://via.placeholder.com/200?text=USB+Drive" },
    { id: 15, name: "Charger", price: 39, image: "https://via.placeholder.com/200?text=Charger" },
    { id: 16, name: "Power Bank", price: 59, image: "https://via.placeholder.com/200?text=Power+Bank" },
  ];

  const handleAddToCart = (product) => {
    alert('${product.name} added to cart!');
    // Later, you can integrate this with your Cart page and backend
  };

  return (
    <div className="shop-container" style={{ padding: "20px" }}>
      <h2>Shop Page</h2>
      <div
        className="products-grid"
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
          gap: "20px",
        }}
      >
        {products.map((product) => (
          <div
            key={product.id}
            className="product-card"
            style={{
              border: "1px solid #ccc",
              borderRadius: "8px",
              padding: "10px",
              textAlign: "center",
              boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
            }}
          >
            <img
              src={product.image}
              alt={product.name}
              style={{ width: "100%", height: "150px", objectFit: "cover", marginBottom: "10px" }}
            />
            <h3>{product.name}</h3>
            <p>${product.price}</p>
            <button
              style={{
                padding: "8px 12px",
                backgroundColor: "#007bff",
                color: "#fff",
                border: "none",
                borderRadius: "5px",
                cursor: "pointer",
              }}
              onClick={() => handleAddToCart(product)}
            >
              Add to Cart
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Shop;
